mapper.select:
select dr.id, dr.patient_id as patientId, dr.create_time as createTime, dr.end_attendance as endAttendance, dr.status, dr.skd_id as skdId, dr.need_book as needBook, dr.bind_status as bindStatus, dr.dept_id as deptId, dr.attendance_date as attendanceDate, dr.patient_age_str as patientAgeStr, p.name as patientName, p.medical_record_no as medicalRecordNo, p.date_of_birth as dateOfBirth, case when p.gender = 1 then '男' when p.gender = 0 then '女' else '—' end as genderStr, d.name as deptName, skd.staff_id as doctorId, s.name as doctorName, skd.noon as noon from dms_registration dr left join pms_patient p on dr.patient_id = p.id left join sms_dept d on dr.dept_id = d.id left join sms_skd skd on dr.skd_id = skd.id left join sms_staff s on skd.staff_id = s.id
and (p.name like concat('%', #{keyword}, '%') or p.medical_record_no like concat('%', #{keyword}, '%'))
order by dr.create_time desc limit #{limit} offset #{offset}

mapper.update:
update dms_registration
set bind_status = #{bindStatus}
where id = #{id}

update dms_registration
set
    status = #{status},
    end_attendance = #{endAttendance}
where id = #{id}

mapper.select:
select dr.id as id, p.medical_record_no as medicalNo, p.name as name, case when p.gender = 1 then '男' else '女' end as gender, COALESCE(TIMESTAMPDIFF(YEAR, p.date_of_birth, dr.attendance_date), 0) as age, dr.status as status, dr.end_attendance as endAttendance, skd.noon as noon from dms_registration dr left join pms_patient p on dr.patient_id = p.id left join sms_skd skd on dr.skd_id = skd.id where dr.attendance_date = #{attendanceDate}
and skd.noon = #{noon}
and (dr.end_attendance = #{endAttendance} or dr.end_attendance is null) and dr.status <> #{canceledStatus}
and skd.staff_id = #{staffId}
and dr.dept_id = #{deptId}
and (p.name like concat('%', #{keyword}, '%') or p.medical_record_no like concat('%', #{keyword}, '%'))
order by dr.create_time asc

mapper.update:
update dms_registration dr
join sms_skd skd on dr.skd_id = skd.id
set dr.status = #{status}
where dr.id = #{id}
  and skd.staff_id = #{staffId}
  and dr.status = #{unfinishedStatus}
  and (dr.end_attendance = #{unfinishedEndAttendance} or dr.end_attendance is null)
  and dr.status <> #{canceledStatus}

update dms_registration dr
join sms_skd skd on dr.skd_id = skd.id
set
    dr.end_attendance = #{endAttendance},
    dr.status = #{status}
where dr.id = #{id}
  and skd.staff_id = #{staffId}
  and (dr.end_attendance = #{unfinishedEndAttendance} or dr.end_attendance is null)
  and dr.status <> #{canceledStatus}

update dms_registration dr
set
    dr.end_attendance = #{endAttendance},
    dr.status = #{status}
where dr.id = #{id}
  and dr.dept_id = #{deptId}
  and (dr.end_attendance = #{unfinishedEndAttendance} or dr.end_attendance is null)
  and dr.status <> #{canceledStatus}

update dms_registration dr
set dr.status = #{status}
where dr.id = #{id}
  and dr.dept_id = #{deptId}
  and dr.status = #{unfinishedStatus}
  and (dr.end_attendance = #{unfinishedEndAttendance} or dr.end_attendance is null)
  and dr.status <> #{canceledStatus}
